import{_ as t,o as n,c as a,a3 as o}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"102. Workload Management","description":"","frontmatter":{"title":"102. Workload Management","eba":"Mental Health Services 2024-2028","topics":["hours","shift-work","staffing","education-pd"]},"headers":[],"relativePath":"ebas/mental-health/rpn-pen-mho/classification-staffing/102-workload-management.md","filePath":"ebas/mental-health/rpn-pen-mho/classification-staffing/102-workload-management.md"}'),s={name:"ebas/mental-health/rpn-pen-mho/classification-staffing/102-workload-management.md"};function r(i,e,l,p,h,d){return n(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="_102-workload-management" tabindex="-1">102. Workload Management <a class="header-anchor" href="#_102-workload-management" aria-label="Permalink to &quot;102. Workload Management&quot;">​</a></h1><p><strong>102.1</strong> Minimum Bed-Based Staffing Profiles</p><p><strong>(a)</strong> The required minimum bed-based staffing profiles (minimum staffing profiles) are contained within <a href="/eba/ebas/mental-health/schedules/10-minimum-staffing-levels.html">Schedule 10</a>. This reflects the agreed minimum number of nursing positions that are rostered per shift to support each consumer consistent with both the professional standards and treatment/program provided by the unit. The minimum staffing profiles are also established to provide sufficient time to enable all Employees to complete all regular organisation commitments,</p><p>professional development/training and all necessary documentation within the normal shift length.</p><p><strong>(b)</strong> For the purposes of the staffing profiles, the following roles are not included within the required minimum staffing profile: RUSONS, PQEN, Group/Activities Nurse Graduate Support Nurses, Clinical Educator, Clinical Consultant, Senior Psychiatric Nurse, a nurse whilst undertaking the duties of a preceptor (and only for periods during which they are not allocated a patient/client load), Surgery Nurse, Discharge Planning Nurse of a Nurse whose sole function is that of an ECT Nurse. These roles are in addition to the minimum staffing profiles.</p><p><strong>(c)</strong> The minimum staffing profiles are a minimum requirement only and it is not intended to prevent the Employer from staffing a ward/unit with additional nurses beyond the number required by the minimum staffing profile.</p><p><strong>102.2</strong> Maintenance of Minimum Bed-Based Staffing Profiles</p><p><strong>(a)</strong> In the event that a vacancy (extended or permanent) occurs on the roster the Employer must take all reasonable steps to fill the vacancy in accordance with the following applicable provisions:</p><p><strong>(i)</strong> <a href="/eba/ebas/mental-health/common-terms/staffing/55-recruitment-to-vacant-position.html">Clause 55</a> Recruitment to Vacant Positions</p><p><strong>(ii)</strong> Clause 102A.5 Backfill of Extended Leave</p><p><strong>(iii)</strong> Clause 102A.1 Replacing Unplanned Absences – bed based services and Clause 102A.3 Use of bank or agency staff.</p><p><strong>102.3</strong> Exception to Staffing Profile Requirement If the Employer has made a reasonable effort in accordance with sub-clause 102.2 the Employer will not be considered to be in breach of sub-clause 102.1 where:</p><p><strong>(a)</strong> Additional nursing staff are not available; or</p><p><strong>(b)</strong> Nursing staff are redeployed, to another area with a greater clinical need (insofar as reasonable efforts per clause 102.2 have been made in both areas and have been unsuccessful); or</p><p><strong>(c)</strong> Beds are closed by the Employer and therefore unavailable to be occupied, subject to consultation with Unions in accordance with <a href="/eba/ebas/mental-health/common-terms/consultation-disputes/18-consultation.html">clause 18</a> (Consultation); or</p><p><strong>(d)</strong> Employees commence no later than 2 hours after the commencement of the shift to avoid fatigue risks arising from not having a 10-hour break. This sub-clause does not apply to night shift; or</p><p><strong>(e)</strong> Other reasons where the circumstance is beyond the control of the Employer (such as a natural disaster) and therefore the failure to meet the staffing profile has not occurred in a serious and wilful manner. If the circumstance is prolonged, this will trigger the consultation provisions of the Agreement.</p><p><strong>(i)</strong> There will be no reduction in the staffing allocation as a direct result of the implementation of this agreement.</p><p><strong>(ii)</strong> Where any change to the size of the unit is proposed that will have the effect of requiring more or less staff, the consultation processes of <a href="/eba/ebas/mental-health/common-terms/consultation-disputes/18-consultation.html">clause 18</a> (Consultation) will apply prior to any such change occurring.</p><p><strong>102.4</strong> Acute Inpatient Units</p><p><strong>(a)</strong> The following principles shall apply to the staffing allocation:</p><p><strong>(i)</strong> Unit Managers shall not carry a caseload.</p><p><strong>(ii)</strong> The prime function of the ANUM is to be recognised as the Shift Leader.</p><p><strong>(iii)</strong> Where a patient is required to be provided with one-to-one support/specialling an additional nurse shall be engaged where appropriate.</p><p><strong>(iv)</strong> Where a nurse is required to provide one to one support/specialling to a client/patient that nurse is not required to perform any other task whilst performing that function.</p><p><strong>(v)</strong> Nursing staff levels and numbers are to be maintained on weekends at the same level as weekdays throughout the year.</p><p><strong>(vi)</strong> A ward clerk shall be employed on each unit/ward.</p><p><strong>(vii)</strong> Additional staffing may be engaged when considered clinically appropriate.</p><p><strong>102.5</strong> Intensive Care Area An Intensive Care Area (ICA),which includes a High Dependency Unit (HDU),ECU, Flexi Care, Acute Management Areas, Low Stimulus or HDU swing beds (however else described) is a designated area within an in-patient unit that has higher levels of nursing staff available providing for the potential to be locked and used as an intervention for a patient/client requiring increased observation, specialist nursing interventions and support.</p><p><strong>(a)</strong> The premise behind a patient/client being placed in a HDU is that a &#39;significant risk&#39; or &#39;significant disruption&#39; exists. The description of &#39;significant&#39; is to be considered in the context of the normal level or levels of acuity within the main ward environment of the in-patient unit.</p><p><strong>(b)</strong> The staffing allocation in clause 102.4 includes High Dependency Units.</p><p><strong>(c)</strong> Each Employer who operates a ICA will be required to adhere to health and safety standards and requirements for Employees working within a ICA.</p><p><strong>(d)</strong> Within the staffing allocation referred to in clause 102.4, the following numbers of nursing staff will be rostered to the ICA: Number of beds Minimum Number of Nurses for ICA 1-2 beds 1 nurse 3-5 beds 2 nurses 6-7 beds 3 nurses 8-9 beds 4 nurses 10 beds or more 1 nurse per 2 beds</p><p><strong>(e)</strong> Local ICA policies and/or agreements shall include (but are not limited to) the following health and safety principles:</p><p><strong>(i)</strong> At least the numbers of nurses specified in clause (d) above shall be allocated/rostered to a ICA, unless determined by the ANUM (shift leader) as being clinically unwarranted.</p><p><strong>(ii)</strong> Local ICA policies and agreements will inform engagement of additional nursing staff.</p><p><strong>(iii)</strong> The number of patients/clients being supported in a ICA should be consistent with the number of available beds, other than in exceptional circumstances.</p><p><strong>(iv)</strong> Staff rostered in a ICA should have appropriate training and experience as a Psychiatric Nurse and expertise in all aspects of prevention and management of aggression.</p><p><strong>(v)</strong> Where practicable, the Employer shall not use casual or agency staff in an ICA, unless such staff are sufficiently trained and experienced.</p><p><strong>(vi)</strong> The Employer must not roster or allocate student nurses to a ICA</p><p><strong>(vii)</strong> Staff should only be rostered/allocated to ICA for periods of up to 4 hours per shift unless otherwise agreed between the individual nurse and the shift leader.</p><p><strong>(f)</strong> Where there are reduced number of patients in ICA, nurses allocated to ICA may remain within the ICA to work intensively with the patients, or if acuity allows, may assist elsewhere within the unit as determined by the ANUM (shift leader). Should the number of patients increase within the ICA whilst a staff member is assisting elsewhere in the unit, they are to return to the ICA.</p><p>102A.Staff Replacement</p><p><strong>102A.1</strong> Replacing unplanned absences – bed-based services</p><p><strong>(a)</strong> Reasonable effort to replace with permanent employee</p><p><strong>(i)</strong> In the event a vacancy occurs on the roster arising from an unplanned absence of the rostered employee, a reasonable effort must be made to fill the vacancy with a permanent employee working no less than the same shift length as was rostered.</p><p><strong>(b)</strong> In this sub-clause, a reasonable effort means:</p><p><strong>(i)</strong> contacting nurses who are available including in accordance with the supplementary roster</p><p><strong>(ii)</strong> if the shift is not filled, seeking to allocate a permanent Pool Employee (where relevant)</p><p><strong>(iii)</strong> if the shift is not filled, seeking to fill the position via a casual bank.</p><p><strong>(c)</strong> The Employer will document its attempts to replace the vacancy which must be available for inspection by the Union and local Union representatives upon request.</p><p><strong>102A.2</strong> Replacing unplanned absences – Community Mental Health Teams</p><p><strong>(a)</strong> Employers will have regard to team vacancies, existing workload and the availability of suitable internal employees when considering whether to backfill unplanned vacancies in Community Teams.</p><p><strong>(b)</strong> Where backfill is not provided, the Employer will consult with Employees and implement measures to mitigate any increase to workload as a result of the backfill not being provided.</p><p><strong>102A.3</strong> Use of bank or agency staff Where, after a reasonable effort under subclause 102A.1(b)has been undertaken the Employer cannot obtain a permanent employee, the rostered shift can be filled by an agency staff member.</p><p><strong>102A.4</strong> Dispute Resolution Disputed matters will be resolved in accordance with the dispute settlement procedure of this Agreement.</p><p><strong>102A.5</strong> Backfilling of Extended Leave Absences</p><p>See also <a href="/eba/ebas/mental-health/rpn-pen-mho/education-pd/99-professional-development-leave.html">clause 99</a> (Professional Development and Associated Entitlements) in relation to leave arising under Section 2, Part G – Professional Development and Associated Entitlements Employers will make every endeavour to provide backfill for leave absences of longer than a week.</p><p><strong>(a)</strong> Bed Based Services</p><p><strong>(i)</strong> In order to maintain the nursing hours provided by the staffing profile, the rostered hours of all Employees who are on Extended Leave will be fully replaced.</p><p><strong>(ii)</strong> Extended Leave means a notification from the Employee to the Employer that they will be absent on Long Service Leave, Annual Leave, Parental Leave, long term WorkCover, Personal Leave or other approved leave absences for a minimum period of a week.</p><p><strong>(iii)</strong> The backfill process must begin as soon as notification of an Extended Leave of absence is received by the manager having regard to the following: <strong>(A)</strong> Part-time employees will be offered an opportunity to back fill the Extended Leave absences in the first instance <strong>(B)</strong> Pool Employees (where relevant) will be offered an opportunity next <strong>(C)</strong> Casual Employees will be asked last.</p><p><strong>(iv)</strong> If backfill is unable to be provided, evidence of the process must be provided to the employee, and/or the unions upon request.</p><p><strong>(b)</strong> Community Mental Health Teams Employers will make every endeavour to provide a backfill for Extended Leave absences greater than one week, within a Community Mental Health Team (CMHT)</p><p><strong>(c)</strong> Extended Leave means a notification from the Employee to the Employer that they will be absent on Long Service Leave, Annual Leave, Parental Leave, long term WorkCover, Personal Leave or other approved leave absences for a period greater than a week.</p><p><strong>(d)</strong> The backfill process must begin as soon as notification of an Extended Leave of absence is received by the manager.</p><p><strong>(e)</strong> Part-time employees will be offered an opportunity to backfill the Extended Leave absences in the first instance.</p><p><strong>(f)</strong> Where the Extended Leave absence is for a period of more than 8 weeks, the Employer will also advertise to backfill the position externally as soon as notification of the Extended Leave absence is notified.</p><p><strong>(g)</strong> Where backfill is not provided, the Employer must:</p><p><strong>(i)</strong> consult with Employees and implement measures to mitigate any increase to workload as a result of the backfill not being provided; and</p><p><strong>(ii)</strong> upon request, provide evidence to demonstrate its endeavours to backfill the Extended Leave of absence.</p>',71)])])}const g=t(s,[["render",r]]);export{f as __pageData,g as default};
